                                            {Array.from({ length: Math.min(5, totalClosurePages) }, (_, i) => {
                                                let p = i + 1; if (totalClosurePages > 5 && closurePage > 3) p = closurePage - 2 + i; if (p > totalClosurePages) p = totalClosurePages - (4 - i); if (p < 1) p = i + 1;
                                                return (<button key={p} onClick={() => setClosurePage(p)} className={`w-7 h-7 rounded text-[10px] font-bold border transition-all ${closurePage === p ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 hover:border-indigo-400'}`}>{p}</button>);
                                            })}
                                        </div>
                                        <button onClick={() => setClosurePage(p => Math.min(totalClosurePages, p + 1))} disabled={closurePage === totalClosurePages} className="p-1.5 rounded-lg border border-slate-200 bg-white hover:bg-slate-50 disabled:opacity-50 transition-colors"><ChevronRight size={16} /></button>
                                    </div>
                                </div>
                            )}
                        </div>
                    </section>
                )}
            </div>
        </div>
    );
};

