                                        <Area type="monotone" dataKey="Desarrollo" stackId="1" stroke="#3b82f6" fill="#3b82f6" fillOpacity={0.4} />
                                        <Area type="monotone" dataKey="Rev. Interna" stackId="1" stroke="#f59e0b" fill="#f59e0b" fillOpacity={0.4} />
