            return { type, total: docsOfType.length, finished: finishedDocs.length, percent, color: TYPE_COLORS[type], finishedIds: finishedDocs.map(d => d.id), pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id) };
