// Helper function to map scale to a readable label
const getScaleLabel = (scale: string) => {
    switch (scale) {
        case 'ANNUAL': return 'Anual';
        case 'MONTHLY': return 'Mensual';
        case 'WEEKLY': return 'Semanal';
        default: return 'Mensual';
